var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"언니, 당주라는 건 무엇인가요?","JPN":"姉さん、当主とは何ですか？","ENG":"Sis, what does it mean to be Lady Nanahara?","TWN":"姊姊，堂主是什麼？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"음, 가문연합을 대표해서 연합의 사람들을 책임지고 이끄는 사람이야.","JPN":"うーん、連合の代表として連合の人たちを責任をもって率いる人のことよ。","ENG":"Hmm. It means to be responsible for everyone in the Family Alliance.","TWN":"嗯，就是代表家族聯盟，對聯盟的人負起責任，並且帶領大家的人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"어르신들은 언니가 적임자니까 당주가 되는 거래요.","JPN":"みんなは姉さんが適任者だから当主になるのだと言ってました。","ENG":"The adults are saying that you are a perfect fit to be one.","TWN":"長輩們都說姊姊是對的人，說姊姊要成為堂主。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"미안해요. 제가 적임자가 아니라서.","JPN":"ごめんなさい。私が適任者ではなくて。","ENG":"I'm sorry that I wasn't chosen.","TWN":"對不起，我不是對的人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"다른 사람들을 모두 책임지면, 언니가 무척 힘들 텐데……","JPN":"他の人たち全員の責任を取ったら、姉さんがとても辛くなります……","ENG":"It seems awfully hard to be responsible for everyone...","TWN":"要對那麼多人負責，姊姊會很辛苦的……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"조금 바빠지긴 하겠지만 괜찮아.","JPN":"ちょっと忙しくなるだろうけど大丈夫よ。","ENG":"I might be a little busy, but it's okay.","TWN":"是會變得有點忙，但沒關係的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"치후유가 곁에 있는데, 언니가 힘들 리가 없잖니?","JPN":"千冬がそばにいるのに、私が辛いわけないでしょう？","ENG":"You're by my side, Chifuyu. So how hard can it be?","TWN":"有千冬在姊姊身邊，姊姊怎麼會辛苦呢？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"언니가 당주님이 되면…… 이제 예전처럼 지낼 수는 없는 거죠?","JPN":"姉さんが当主になったら……もう昔のようには過ごせないのですよね？","ENG":"If you become the head of Nanahara... does that mean we can't be friends anymore?","TWN":"姊姊成為堂主後……我們就沒辦法像以前一樣相處吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"치후유. 이리 와봐.","JPN":"千冬。こっちおいで。","ENG":"Chifuyu, come here.","TWN":"千冬，你過來。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"어때?","JPN":"どう？","ENG":"How does that feel?","TWN":"感覺怎麼樣？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"따뜻하고, 편안해요. 그야 치나츠 언니의 품이니까요.","JPN":"温かくて、心地いいです。そりゃあ、千夏姉さんの腕の中ですから。","ENG":"It's warm and comfy. Because it's a hug from you.","TWN":"因為是千夏姊姊的擁抱，感覺好溫暖、好安心。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"후후……","JPN":"ふふ……","ENG":"Hah hah.","TWN":"呵呵……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"이렇게 다른 옷을 입고, 당주님이라고 불려도 언니는 변함없이 치후유의 언니야.","JPN":"こうして違う服を着て、当主と呼ばれても私は変わらず千冬の姉さんよ。","ENG":"Even if I wear different clothes, and people call me Lady Nanahara, it doesn't change the fact that I am still your sister.","TWN":"就算我換上不同的衣服，大家稱我為堂主，但我還是千冬的姊姊，這一點是不會改變的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"예전이랑 똑같아. 아무것도 바뀌지 않아.","JPN":"昔と同じ。何も変わらない。","ENG":"It's going to be just as it was. Nothing is going to change.","TWN":"和以前一樣，不會有任何改變。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"그리고……","JPN":"それに……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"사람에겐 각자 주어진 운명이 있는 거라고 해.","JPN":"人にはそれぞれ与えられた運命があるんだって。","ENG":"Each and every one of us is given a fate.","TWN":"每個人的命運都不同，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"나는 원래 당주가 될 운명이었으니, 치후유가 미안해할 필요는 없어.","JPN":"私は元々当主になる運命だったから、千冬が悪く思う必要なんかないのよ。","ENG":"I was destined to become the head of Nanahara. So you don't have to be sorry about that.","TWN":"而我的命運就是要成為堂主，所以千冬你無需道歉。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"평생 그토록 많은 무게를 견뎌내고도……","JPN":"一生それほどたくさんのものに耐えて……","ENG":"After enduring all that burden your entire life...","TWN":"你這輩子已經承擔那麼多重任……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"왜 혼자서만 모든 걸 짊어지는 건가요.","JPN":"どうして一人ですべてを背負おうとするのですか。","ENG":"Why do you still choose to bear it alone...?","TWN":"為什麼還要自己背負一切呢？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……언니.","JPN":"……姉さん。","ENG":"...Chinatsu.","TWN":"……姊姊。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"나나하라 당주의 상태는 어떠냐?","JPN":"七原家当主の状態はどうじゃ？","ENG":"How is Lady Nanahara's condition?","TWN":"七原堂主的情況如何？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"긴급한 조치는 모두 취했지만, 의식이 깨어나기 전까진 장담드릴 수 없습니다.","JPN":"応急処置はすべて行いましたが、意識を取り戻すまでは何ともいえません。","ENG":"She is stable, but they cannot guarantee if she will regain consciousness.","TWN":"已經進行急救，但在恢復意識之前，誰也無法保證。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"결계를 복원하기 위해서 한꺼번에 너무 많은 CRF를 소비했어요.","JPN":"結界を復元するために一気に大量のCRFを消耗しました。","ENG":"She used up too much of her CRF at once to restore the barrier.","TWN":"因為復原結界一下消耗太多CRF。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……CRF뿐만이 아니겠지. 임시라고는 했지만 결계를 유지하는 건 영혼을 연료처럼 태우는 일이니 말이야.","JPN":"……CRFだけではあるまい。臨時とは言ったが、結界を維持することは魂を燃料のように燃やすことじゃからのう。","ENG":"...It's not just her CRF. Although temporary, maintaining the barrier burns the soul like fuel.","TWN":"……不只是CRF的關係，雖說是暫時的，但靈魂如同維持結界的燃料，等於是在耗損她的靈魂。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"서둘러 결계옥을 되찾지 못하면…… 그땐 나나하라 당주의 영혼이 먼저 닳아 없어지고 말 거다.","JPN":"急いで結界玉を取り戻さないと……七原家当主の魂が先にすり減ってしまうぞ。","ENG":"If we don't hurry and find Akaitama... her soul will wither and disappear.","TWN":"要是不儘快找回結界玉石……恐怕到時候七原堂主的靈魂會先耗盡。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하바키의 모략자들은 아직 모습을 드러내지 않는군요.","JPN":"覇吐の謀略者たちはいまだに現れていませんね。","ENG":"Habaki's schemers are still nowhere to be found.","TWN":"幅木的同夥還沒現身，"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저희가 결계를 수복하는 것 또한 그들의 계획대로라는 거겠죠.","JPN":"私たちが結界を修復することもまた、彼らの計画どおりということでしょう。","ENG":"That leads me to believe it was their plan for us to restore the barrier.","TWN":"這就表示，我們修復結界這件事也在他們預料之內。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"우리가 하루빨리 결계옥을 되찾아야만 하는 이유를 만드는 거겠지.","JPN":"わしらが一刻も早く結界玉を取り戻さねばならない理由を作っているのじゃろう。","ENG":"Only to force our hand in trying to find Akaitama.","TWN":"意思就是我們必須早日找回結界玉石。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하지만 놈들의 목적이 정말로 역신을 깨우는 것이라면……","JPN":"だがあやつらの目的が本当に疫病神を目覚めさせることなら……","ENG":"However, if their main goal is to revive the Plague God...","TWN":"不過若他們的目的真的是要喚醒瘟神……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"명부신이 예견한 세번째 위기가 봉착하고 만다.","JPN":"冥府の神が予言した三度目の危機が訪れてしまう。","ENG":"That means the Nether God's prediction of a third disaster is nearing.","TWN":"那這就是冥府神預言的第三個危機。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유……?","JPN":"千冬……？","ENG":"Chifuyu...?","TWN":"千冬……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님? 정신이 드십니까?","JPN":"当主？　気がつきましたか？","ENG":"My lady! Are you all right?","TWN":"堂主？您醒了？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"결계는…… 어떻게 됐나요?","JPN":"結界は……どうなりましたか？","ENG":"The barrier... Did it work?","TWN":"結界……情況如何？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"결계는 재가동 됐고, 사령들은 물러났습니다.","JPN":"結界は再稼働し、邪霊は退きました。","ENG":"The barrier is working again, and the Ghouls have retreated.","TWN":"結界重新運作中，邪靈也都回到它們原本的地方。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다행이네요. 이제 신기를 되찾기만 하면 되겠어요.","JPN":"安心しました。あとは神器を取り戻すだけですね。","ENG":"That is good news. Now, all we have to do is retrieve the Sacred Treasure back.","TWN":"那就好，那接著就是要把神器找回來。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……하바키가 저에게 그런 말을 남기더군요.","JPN":"……覇吐が私にこう言っていました。","ENG":"...Habaki said something to me.","TWN":"……幅木死前對我說過，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가 신의 그릇이며…… 역신을 깨우게 두지 않겠다고요.","JPN":"私が神の器であり……疫病神を呼び覚ますようにはさせないと。","ENG":"That I was the god's vessel... That he would not allow the Plague God to be resurrected.","TWN":"他說我是神的器皿……還說他不會讓我喚醒瘟神。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"혹시 당주님께선 짚이는 것이 있으십니까?","JPN":"もしや当主にお心当たりはありますか？","ENG":"Does that mean anything to you, my lady?","TWN":"堂主有想到什麼嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아닙니다. 제가 괜한 소릴 했군요.","JPN":"いえ、気にしないでください。余計なことを申し上げました。","ENG":"Never mind. I misspoke.","TWN":"沒事，當我沒說。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"역시 그 자가 죽어가기 전에 헛소리를 늘어놓았다고 밖에……","JPN":"やはりあの者が死ぬ前にでたらめを言ったとしか……","ENG":"I can only assume that they were the last words of a senile man...","TWN":"應該就是他死前在胡言亂語……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……어떤 의미인지 알아요.","JPN":"……どんな意味かわかります。","ENG":"...I do know what he meant.","TWN":"……我知道他的意思。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예……?","JPN":"はい……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"예정에 없던 가문의 아이가 태어나……","JPN":"前例のない子どもが生まれ……","ENG":"The unexpected child...","TWN":"不在家族預期內出生的孩子……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……역신을 깨우리라.","JPN":"……疫病神の眠りを覚ますだろう。","ENG":"...shall awaken the Plague God.","TWN":"……，會喚醒瘟神。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그 <color=#ffd34c>아이</color>가 바로 치후유입니다.","JPN":"その<color=#ffd34c>子</color>が千冬です。","ENG":"That <color=#ffd34c>child</color> is you, Chifuyu.","TWN":"那個<color=#ffd34c>孩子</color>就是千冬。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님……? 갑자기 무슨 말씀을……?","JPN":"当主……？　急に何を……？","ENG":"My lady...? I don’t understand...","TWN":"堂主……？您怎麼突然說這些……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나나하라 가문에선 지금껏 단 한 번도 쌍둥이가 태어난 적이 없습니다.","JPN":"七原家には今までたった一度も双子が生まれたことはありません。","ENG":"Never have twins been born in the Nanahara family.","TWN":"七原家族中從未有過產下雙胞胎的前例，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"적어도, 당주들이 예견해온 운명의 아이는 언제나 한 명이었습니다.","JPN":"少なくとも、当主たちが予言してきた運命の子はいつも一人でした。","ENG":"At least... the head of the family had always prophecized one destined child.","TWN":"歷代堂主預言的命運之子都只有一位。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 저희 어머니께서 태어나시던 날도, 어머니께서 저희를 낳으시던 날에도……","JPN":"ですが、お母様が生まれた日も、お母様が私たちを産んだ日も……","ENG":"However, the day when our mother was born... and the day she gave birth to us...","TWN":"但是媽媽出生時，或是媽媽在生我們時……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……주어진 운명은 하나뿐이었으나, 태어난 것은 한 사람이 아니었어요.","JPN":"……与えられた運命は一つだけでしたが、生まれたのは一人ではありませんでした。","ENG":"...Fate was for one, but two were born.","TWN":"……命中注定的孩子都只有一位，生下的卻不只一個。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님……? 늦은 밤 중에 이런 누추한 집에는 어쩐 일이신지요?","JPN":"当主……？　このような夜中にむさ苦しいこの家までお越しになるとは。","ENG":"Lady Nanahara...? What brings you here when the moon is high?","TWN":"堂主……？您怎麼會這麼晚的時間來找我？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_WOOD"},{"id":"L25_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"미안해요, 사나에.","JPN":"ごめんなさい、早苗。","ENG":"My apologies, Sanae.","TWN":"對不起，早苗。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"바람의 목소리를 따라가다 보니, 의지할 수 있는 사람이 당신 밖에 없었어요.","JPN":"風の声について行ってみたら、頼れる人があなたしかいなかったのです。","ENG":"I was following the voice of wind, and you were the only person I could rely on.","TWN":"我跟著風聲後發現，我能倚靠的人就只有你。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"저희가 태어나는 날, 어머니는 불길함을 느끼고 연합원들 몰래 영지 밖으로 나오셨어요.","JPN":"私たちが生まれた日、お母様は不吉を感じて連合員に内緒で領地の外に出ました。","ENG":"The day we were born, Mother felt an omen and secretly snuck out of home.","TWN":"在我們出生那一天，媽媽有股不好的預感，因此瞞著聯盟成員去到領地外。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 봉인역의 숲에 거처를 두고 지내던 사나에를 찾아갔죠.","JPN":"そして封印域の森で暮らしていた早苗を訪ねたのです。","ENG":"She went to Sanae, who was living in the woods of the Seal Domain.","TWN":"她離開領地後便去找住在封印域森林裡的早苗。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"첫번째로 태어난 아이가 울음을 터뜨렸어요.","JPN":"最初に生まれた子が泣き始めました。","ENG":"The first born cried as she came out into the world.","TWN":"第一個出生的孩子哇哇大哭，"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 두번째 아이는 아무런 목소리도 내지 못했습니다.","JPN":"ですが次に生まれた子は何の声も出せませんでした。","ENG":"But the second... could not even make a sound.","TWN":"但二個出生的孩子卻一點聲音也沒有。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"숨을 쉬지 않는군요.","JPN":"息をしておりません。","ENG":"She is not breathing.","TWN":"她已經沒了呼吸，"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"안타깝지만, 이미 늦은 것 같습니다.","JPN":"残念ですが、遅かったようです。","ENG":"I am sorry, but I think it is too late.","TWN":"我很遺憾，恐怕為時已晚。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"부탁해요, 사나에. 이 일은 비밀로 해주세요.","JPN":"お願いします、早苗。このことは内緒にしてください。","ENG":"Please, Sanae. Do not tell anyone about this.","TWN":"早苗，拜託你，這件事請替我保密。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"예? 그게 무슨 말씀이신지……","JPN":"はい？　それはどういう……","ENG":"I beg your pardon? I do not understand...","TWN":"保密？這是什麼意思……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님?!","JPN":"ご当主様！？","ENG":"Lady Nanahara?!","TWN":"堂主？！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"무모합니다! 신력을 사람에게 함부로 쓰시다니요! 그 위험을 알고 계시는 겁니까?","JPN":"無茶です！　神力を人に使うなど！　どれほど危険なことかご存じでないのですか？","ENG":"This is beyond reckless! Using divine powers on another human! Do you not realize the risks involved?","TWN":"荒唐！竟然要對人使用神力！堂主知道這有多危險嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"제가 어렸을 때, 어머니께선 종종 그런 말씀을 하셨죠.","JPN":"私が幼かった頃、母上はよくこうおっしゃってました。","ENG":"When I was young, my mother would often say these words to me.","TWN":"在我小的時候，媽媽總是跟我說，"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"너에게 동생이 있었더라면 참 좋았을 텐데…… 라고요.","JPN":"あなたに妹がいたら本当によかったのに……と。","ENG":"\\"It would have been nice if you had a sibling...\\"","TWN":"要是你有妹妹的話不知道有多好……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"그리고는 저에게 한 마디 없이 숲으로 산책을 나가곤 하셨는데.","JPN":"そして私には一言もいわず森に散歩に出られました。","ENG":"Then, she would go for a walk in the wood without saying another word.","TWN":"而且媽媽經常沒跟我說一聲就到森林裡去散步。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"몰래 따라갔더니, 어머니 앞에 이름 없는 묘비가 하나 있더라고요.","JPN":"こっそりついて行ったら、母上は名の無い墓石の前にいらっしゃいました。","ENG":"I followed her one day, and there was an unmarked grave in front of her.","TWN":"有一次我偷偷跟在她後面，發現媽媽來到一個無名氏的墓碑前。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"기껏 태어나 빛도 못 보고 죽을 운명이라니…… 그런 건 너무 가혹하잖아요.","JPN":"せっかく生まれたのに光を見ることもかなわず死ぬ運命だなんて……それではあまりにも酷です。","ENG":"A life born fated to die, without even seeing the light of this world... How cruel is that?","TWN":"好不容易才出生在這個世界，結果眼睛都還沒睜開就死掉……這樣豈不是太殘忍？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……다른 당주들이 이 사실을 알게 된다면 분명 그 아이를 가만히 두지 않을 것입니다.","JPN":"……他の当主がこの事実を知れば、きっとこの子を放ってはおかないでしょう。","ENG":"...If the other family leaders find out about this, they will not leave this child alone.","TWN":"……要是其他堂主這件事，肯定不會輕易放過她的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"그래서 당신을 찾아왔어요. 의지할 수 있는 사람이라고 생각했으니까요.","JPN":"それであなたを訪ねたのです。頼れる人だと思いましたから。","ENG":"That is why I came to you. You are the only person I can trust.","TWN":"所以我才來找你，因為我知道你靠得住。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"제 어미가 저지른 불충을 아시면서도…… 그런 말씀을 하시는 겁니까?","JPN":"私の母が犯した不忠をご存じの上で……そのようなことをおっしゃるのですか？","ENG":"You are aware of what my mother has done... And yet, you trust me?","TWN":"您明知道家母是個不忠的人……還這麼說嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"사나에.","JPN":"早苗。","ENG":"Sanae.","TWN":"早苗。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"저는 당주라는 이름을 걸치고 있지만, 사요 장로의 뜻대로 움직이는 꼭두각시일 뿐입니다.","JPN":"私は当主という名を持っていますが、小夜長老の思うがままに動く操り人形に過ぎません。","ENG":"Even though I am the head of Nanahara, I am merely a puppet than does as ordered by Elder Sayo.","TWN":"雖然大家都稱呼我為堂主，但事實上我只是一個聽命於小夜長老的魁儡。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"제가 스스로 결정할 수 있는 일은 그리 많지 않아요.","JPN":"私が自分で決められることはそう多くないのです。","ENG":"There are not many decisions I can make on my own.","TWN":"我能決定的事少之又少。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"하지만 적어도…… 제 아이만큼은 제 의지로 살리고 싶었어요.","JPN":"ですが少なくとも……自分の子どもだけは自分の意思で生かしたかった。","ENG":"However... she is still my child, and I want her to live.","TWN":"但至少……我孩子的死活我能自己決定。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"이 뒤는 그대의 뜻에 맡길게요.","JPN":"この後はあなたの意志にお任せします。","ENG":"I will leave the rest up to you.","TWN":"後面的事就照你的意思做。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"그대가 아이를 위험하다고 판단하여 처분하더라도…… 원망하지 않겠어요.","JPN":"そなたがこの子を危険だと判断して処分しようとも……恨みません。","ENG":"If you feel the child is dangerous and have to dispose her... I will not hold any resentment.","TWN":"就算你認為這個孩子會招來危險要處理掉她……我也不會有怨言。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"예정에 없던 가문의 아이가 태어나…… 역신을 깨우리라.","JPN":"前例のない子どもが生まれ……疫病神の眠りを覚ますだろう。","ENG":"The unexpected child... shall awaken the Plague God.","TWN":"不在家族預期內出生的孩子……會喚醒瘟神。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"본래 태어나지 못했을 운명의 아이를 당주님께서 바꾸셨으니, 이 예견은 맞아떨어지는 셈이 되지요.","JPN":"本来なら生まれることのなかった子の運命をご当主様が変えたので、この予言は当たることになりました。","ENG":"You have altered the fate of this child, proving the foretelling was true.","TWN":"堂主要救活原本不該出生的孩子，就表示預言是真的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"가문연합의 규율에 어긋나는 존재를 처분하는 것은, 가문연합의 무사로서 마땅한 의무.","JPN":"連合の規律に外れた存在を処分することは、連合の武士として当然の義務。","ENG":"And it is my duty as an Alliance warrior to eliminate any being who violates the Family Alliance's norms.","TWN":"處分違反家族聯盟規定的人，是屬於家族聯盟武士的責任。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"허나, 이 아이를 지금 처분한다 해도 역신은 언젠가 깨어날 것입니다.","JPN":"ですが、この子を今処分したとしても疫病神はいつか目覚めるはずです。","ENG":"Nevertheless, killing her now will not make a difference in the Plague God's awakening.","TWN":"不過，就算現在處理掉這孩子，瘟神總有一天也會甦醒過來。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그렇다면 차라리 저희가 이 아이를 곁에 두고 감시하는 편이 낫겠지요.","JPN":"それならいっそのこと、この子を手元に置いて監視する方がいいと思います。","ENG":"Thus, it would be better for us to keep her by our side and keep a close eye.","TWN":"那倒不如將這孩子留在身邊，好好監視她。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASTER_NPC_NANAHARA_PAST","text":{"KOREA":"……고마워요, 사나에.","JPN":"……ありがとうございます、早苗。","ENG":"...Thank you, Sanae.","TWN":"……謝謝你，早苗。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그 말씀이 거짓이 아니라면…… 왜 지금까지 말씀해주지 않으신 겁니까?","JPN":"そのお言葉が真実なら……どうして今まで話してくれなかったのですか？","ENG":"If what you say is true... why did you not tell me all this time?","TWN":"若這話是真的……那您為何從未向我提起？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저도 얼마 전에야 알게 된 사실이에요.","JPN":"私もつい最近になって知ったのです。","ENG":"I only learned of it myself recently.","TWN":"我也是不久前才知道的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그리고 치후유는 이 사실을 몰랐으면 했습니다.","JPN":"そして千冬はこの事実を知らずにいてくれればと思いました。","ENG":"Also, I did not want you to know, Chifuyu.","TWN":"而且，我不希望你知道這件事。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제가 노력하면 굳이 치후유가 알지 않아도, 이 문제를 해결할 수 있다고 믿었으니까요.","JPN":"私が努力すれば、千冬が知らなくともこの問題を解決できると信じていましたから。","ENG":"I believed that the problem would be resolved if I just worked harder.","TWN":"因為我相信只要我努力，一定可以解決這件事，那就算你不知道也無妨。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"언제까지 그렇게…… 혼자서만 짊어지실 생각입니까?","JPN":"いつまでそうやって……一人で背負うつもりですか？","ENG":"How much longer... are you going to keep bearing the weight on your own?","TWN":"您到底……要獨自承擔一切到什麼時候？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님에게 저는 자신의 운명조차 견디지 못하는 나약한 사람입니까?","JPN":"当主にとって私は自身の運命にも耐えられない軟弱な人間ですか？","ENG":"Do you see me as someone who is not even capable of enduring her own fate?","TWN":"對堂主而言我是這麼軟弱的人嗎？軟弱到無法承擔自己的命運？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 의미가 아니에요, 치후유!","JPN":"そういう意味ではありません、千冬！","ENG":"That is not what I meant, Chifuyu!","TWN":"我不是這個意思，千冬！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"다른 이들의 짐을 혼자만 떠안으면서……!","JPN":"他の者の問題を一人で抱え込んで……！","ENG":"You always take on the burden of others...!","TWN":"為什麼您就是無法理解……！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그걸 지켜보는 사람의 마음은 대체 왜 헤아리지 못하시는 겁니까……?","JPN":"それを見守る者の気持ちはどうしてわかってくださらないんですか……？","ENG":"Yet, you have no consideration for those who are by your side!","TWN":"您獨自背負別人的重擔，這些看在別人眼裡的心情……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"희생을 치르지 않겠다는 약속도 결국, 당주님 홀로 모든 걸 감내한다는 뜻이었습니까?","JPN":"犠牲を払わないという約束も、結局は当主一人ですべてを耐えるという意味だったのですか？","ENG":"Your promise of not making further sacrifices... Did you mean it by enduring everything yourself?","TWN":"您答應我不會再造成犧牲，結果是您要獨自承擔一切的意思嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그게 대체…… 희생과 무엇이 다릅니까?","JPN":"それのどこが……犠牲と違うんですか？","ENG":"Then... how is that any different from a sacrifice?!","TWN":"這到底……與犧牲有何差異？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유……","JPN":"千冬……","ENG":"Chifuyu...","TWN":"千冬……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"알고 있습니다. 제가 당주님에 비해 나약하고, 타고난 것 하나 없다는 것쯤은.","JPN":"わかっています。私が当主に比べれば弱く、生まれつき優れていることも何一つないということくらいは。","ENG":"I know. Compared to you, I am weaker, and not good at anything.","TWN":"我知道，我沒有堂主厲害，沒有任何天賦。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 이래서는……","JPN":"ですがこれでは……","ENG":"But this...","TWN":"這樣的我……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님에게 의지가 되지 못하는 저는……","JPN":"当主が頼ることのできない私は……","ENG":"Seeing you not being able to trust me...","TWN":"無法讓堂主倚靠的我……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"태어나지 않은 것만 못한 처지나 다름없지 않습니까?","JPN":"いないのも同然ではないですか？","ENG":"How is that any different from not being born at all in the first place?!","TWN":"處境不就等於跟沒出生一樣嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……몹시 화가 나신 것처럼 뛰쳐나가시더군요. 처음보는 표정이었습니다.","JPN":"……とても怒って出ていきましたね。初めて見る顔でした。","ENG":"She seemed rather distressed as she stormed out. I have never seen her like this.","TWN":"……她很生氣地衝出去呢，我還是第一次看到她露出那種表情。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"미안해요, 사나에. 치후유에게 그날의 이야기를 전부 털어놓았어요.","JPN":"ごめんなさい、早苗。千冬にあの日のことをすべて話してしまいました。","ENG":"I am sorry, Sanae. I told Chifuyu everything about that day.","TWN":"早苗，對不起，我把那天的事都告訴千冬了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그랬었군요.","JPN":"そうだったのですね。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"치후유님이 그 진실로 말미암아 잘못된 선택을 내릴지도 모릅니다.","JPN":"千冬様がその真実ゆえに間違った選択をするかもしれません。","ENG":"Now knowing the truth, I am worried she might make the wrong decision.","TWN":"我擔心千冬會因為這件事而做出錯誤的決定。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"만일 그렇다고 하더라도……","JPN":"たとえそうだとしても……","ENG":"But even if she does...","TWN":"即便如此……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유에게는 자신의 운명을 알고 대비할 자격이 있으니까요.","JPN":"千冬には自分の運命を知って備える資格がありますから。","ENG":"Chifuyu also deserves to prepare for the fate bestowed upon her.","TWN":"千冬也有權力知道自己的命運，並且做好準備。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제가 앞으로 얼마나 버틸 수 있을지 모르니, 또 치후유가 혼자 남겨질 수도 있다고 생각하니…… 저도 지레 겁이 난 모양이네요.","JPN":"私がこれからどれくらい耐えられるかわかりませんが、千冬が一人になるかもしれないと思うと……私も怖くなったようです。","ENG":"I do not know how much longer I can last. Also, thinking of having to leave her in this world alone... Perhaps I got scared.","TWN":"我或許多少也有點害怕，我怕我不知道還能撐多久……我也怕會留下千冬自己一個人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님은 무사하실 겁니다. 치후유님도 마찬가지고요","JPN":"ご当主様はご無事でしょう。千冬様もです。","ENG":"Lady Nanahara, you will be all right. The same for Miss Chifuyu as well.","TWN":"堂主一定會沒事的，千冬也是。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그럴 지도요.","JPN":"そうかもしれませんね。","ENG":"Perhaps so.","TWN":"希望如此。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이제 운명에 의존하지 않기로 했는데, 미래를 전혀 들을 수 없다고 생각하니 두려워요.","JPN":"もう運命に頼らないと決めたのに、未来を全然聞けないと思うと怖いのです。","ENG":"I decided not to rely on fate anymore, and yet... I am petrified of not being able to hear the future.","TWN":"雖然我決定不再倚靠命運，不過一想到我聽不到未來就覺得很恐懼。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 저희가 맞서야 할 적들은…… 저희가 모르는 미래를 훤히 알고 있겠죠.","JPN":"ですが私たちが立ち向かうべき敵は……私たちが知らない未来を全部知っています。","ENG":"The foes we have to face... They know the future that we do not.","TWN":"但我很清楚，我們要面對的敵人……就是未知的未來。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이미 겪지 않으셨습니까? 미래는 바뀔 수도 있다는 것을.","JPN":"すでに経験なさったではないですか。未来は変わるかもしれないということを。","ENG":"But we have already experienced it, have we not? That the future can be changed.","TWN":"您不是已經經歷過嗎？未來是可以改變的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이번에도 바라고 있어요.","JPN":"今回もそれを望んでいます。","ENG":"I hope it does this time as well.","TWN":"我真希望，"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다시 한번 기적 같은 일이 일어나 운명을 바꾼다면…… 얼마나 좋을까요?","JPN":"もう一度奇跡が起きて運命が変わるのなら……どれほどいいでしょう。","ENG":"How wonderful would it be for miracles to happen... and change our fates?","TWN":"再次發生奇蹟改變命運……這樣該有多好？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};